import 'dart:developer';

import 'package:cloud_firestore/cloud_firestore.dart';
import 'package:firebase_auth/firebase_auth.dart';
import 'package:firebase_core/firebase_core.dart';
import 'package:flutter/foundation.dart';
import 'package:flutter/material.dart';
import 'package:park_place/screens/Home.dart';
import 'package:park_place/screens/HomeUser.dart';
import 'package:park_place/screens/detailsScreen.dart';
import 'package:park_place/screens/mainPage.dart';
import 'package:park_place/screens/parkVehivleHomePage.dart';
import 'package:park_place/screens/parkvehicleDetailPage.dart';
import 'package:park_place/shared/loading.dart';
import 'package:shared_preferences/shared_preferences.dart';

const FirebaseOptions webFirebaseOptions = FirebaseOptions(
  apiKey: 'AIzaSyD65kXoOn8RW9i6EXRKa-4henzFUoaH36M',
  authDomain: 'car-parking-system-42fc0.firebaseapp.com',
  projectId: 'car-parking-system-42fc0',
  storageBucket: 'car-parking-system-42fc0.appspot.com',
  messagingSenderId: '698202999109',
  appId: '1:698202999109:web:placeholder',
);

void main() {
  runApp(MyApp());
}

bool owner = false;

class MyApp extends StatefulWidget {
  const MyApp({Key? key}) : super(key: key);
  @override
  _MyAppState createState() => _MyAppState();
}

class _MyAppState extends State<MyApp> {
  @override
  void initState() {
    checkRole();
    super.initState();
  }

  Future<void> checkRole() async {
    SharedPreferences pref = await SharedPreferences.getInstance();
    owner = (pref.getBool('ownerRole') ?? false);
  }

  Widget build(BuildContext context) {
    final Future<FirebaseApp> _initialization = Firebase.initializeApp(
      options: kIsWeb ? webFirebaseOptions : null,
    );

    return FutureBuilder(
      future: _initialization,
      builder: (context, snapshot) {
        return MaterialApp(
          debugShowCheckedModeBanner: false,
          title: 'ParkPlace',
          theme: ThemeData(
            primarySwatch: Colors.blue,
          ),
          routes: {
            '/detailsScreen': (context) => DetailsScreen(),
            '/mainPage': (context) => MainPage(),
          },
          home: snapshot.connectionState != ConnectionState.done
              ? Loading()
              : snapshot.hasError
                  ? MainPage()
                  : StreamBuilder(
                      stream: FirebaseAuth.instance.authStateChanges(),
                      builder: (context, userSnapshot) {
                        if (userSnapshot.connectionState ==
                            ConnectionState.waiting) {
                          log('Loading');
                          return Loading();
                        } else if (owner) {
                          if (userSnapshot.data != null) {
                            log('Logged in');
                            return StreamBuilder(
                              stream: FirebaseFirestore.instance
                                  .collection("giveplaceusers")
                                  .doc(FirebaseAuth
                                      .instance.currentUser!.phoneNumber)
                                  .snapshots(),
                              builder: (context, snapShot) {
                                if (snapShot.connectionState ==
                                    ConnectionState.waiting) {
                                  return Loading();
                                } else {
                                  if (snapShot.hasData) {
                                    return Home();
                                  }
                                  log('Has no data');
                                  return DetailsScreen();
                                }
                              },
                            );
                          }
                        } else if (!owner) {
                          if (userSnapshot.data != null) {
                            log('Logged in');
                            return StreamBuilder(
                              stream: FirebaseFirestore.instance
                                  .collection("parkvehicleusers")
                                  .doc(FirebaseAuth
                                      .instance.currentUser!.phoneNumber)
                                  .snapshots(),
                              builder: (context, snapShot) {
                                if (snapShot.connectionState ==
                                    ConnectionState.waiting) {
                                  return Loading();
                                } else {
                                  if (snapShot.hasData) {
                                    return HomeUser();
                                  }
                                  log('Has no data');
                                  return ParkDetailsScreen();
                                }
                              },
                            );
                          }
                        }
                        log('UserSnapshot = null');
                        return MainPage();
                      },
                    ),
        );
      },
    );
  }
}

const http = require('http');
const fs = require('fs');
const path = require('path');

const PORT = 5000;
const HOST = '0.0.0.0';
const BUILD_DIR = path.join(__dirname, 'build', 'web');

const mimeTypes = {
  '.html': 'text/html',
  '.js': 'application/javascript',
  '.css': 'text/css',
  '.json': 'application/json',
  '.png': 'image/png',
  '.jpg': 'image/jpeg',
  '.gif': 'image/gif',
  '.svg': 'image/svg+xml',
  '.ico': 'image/x-icon',
  '.wasm': 'application/wasm',
  '.ttf': 'font/ttf',
  '.woff': 'font/woff',
  '.woff2': 'font/woff2',
  '.map': 'application/json',
  '.bin': 'application/octet-stream',
};

const server = http.createServer((req, res) => {
  let urlPath = req.url.split('?')[0];
  if (urlPath === '/') urlPath = '/index.html';

  let filePath = path.join(BUILD_DIR, urlPath);

  if (fs.existsSync(filePath) && !fs.statSync(filePath).isDirectory()) {
    const ext = path.extname(filePath);
    const contentType = mimeTypes[ext] || 'application/octet-stream';
    const data = fs.readFileSync(filePath);
    res.writeHead(200, { 'Content-Type': contentType });
    res.end(data);
  } else {
    const indexPath = path.join(BUILD_DIR, 'index.html');
    const data = fs.readFileSync(indexPath);
    res.writeHead(200, { 'Content-Type': 'text/html' });
    res.end(data);
  }
});

server.listen(PORT, HOST, () => {
  console.log(`ParkPlace app running at http://${HOST}:${PORT}`);
});

