class MyApp extends StatefulWidget {
  const MyApp({Key? key}) : super(key: key);
  @override
  _MyAppState createState() => _MyAppState();
}

class _MyAppState extends State<MyApp> {
  bool _ready = false;

  @override
  void initState() {
    super.initState();
    _waitForFirebase();
  }

  Future<void> _waitForFirebase() async {
    int attempts = 0;
    while (!_firebaseReady && attempts < 30) {
      await Future.delayed(const Duration(milliseconds: 200));
      attempts++;
    }
    if (mounted) {
      setState(() => _ready = true);
    }
  }

  @override
  Widget build(BuildContext context) {
    return MaterialApp(
      debugShowCheckedModeBanner: false,
      title: 'ParkPlace',
      theme: ThemeData(
        primarySwatch: Colors.blue,
      ),
      routes: {
        '/detailsScreen': (context) => DetailsScreen(),
        '/mainPage': (context) => MainPage(),
      },
      home: !_ready
          ? Loading()
          : _firebaseReady
              ? _AuthGate()
              : MainPage(),
    );
  }
}

class _AuthGate extends StatelessWidget {
  @override
  Widget build(BuildContext context) {
    return StreamBuilder(
      stream: FirebaseAuth.instance.authStateChanges(),
      builder: (context, userSnapshot) {
        if (userSnapshot.connectionState == ConnectionState.waiting) {
          return Loading();
        } else if (owner && userSnapshot.data != null) {
          log('Logged in as owner');
          return StreamBuilder(
            stream: FirebaseFirestore.instance
                .collection("giveplaceusers")
                .doc(FirebaseAuth.instance.currentUser!.phoneNumber)
                .snapshots(),
            builder: (context, snapShot) {
              if (snapShot.connectionState == ConnectionState.waiting) {
                return Loading();
              }
              if (snapShot.hasData) {
                return Home();
              }
              return DetailsScreen();
            },
          );
        } else if (!owner && userSnapshot.data != null) {
          log('Logged in as user');
          return StreamBuilder(
            stream: FirebaseFirestore.instance
                .collection("parkvehicleusers")
                .doc(FirebaseAuth.instance.currentUser!.phoneNumber)
                .snapshots(),
            builder: (context, snapShot) {
              if (snapShot.connectionState == ConnectionState.waiting) {
                return Loading();
              }
              if (snapShot.hasData) {
                return HomeUser();
              }
              return ParkDetailsScreen();
            },
          );
        }
        return MainPage();
      },
    );
  }
}

