class _MyAppState extends State<MyApp> {
  final Future<FirebaseApp> _initialization = Firebase.initializeApp(
    options: kIsWeb ? webFirebaseOptions : null,
  );

  @override
  Widget build(BuildContext context) {
    return FutureBuilder(
      future: _initialization,
      builder: (context, snapshot) {
        if (snapshot.connectionState != ConnectionState.done) {
          return MaterialApp(
            debugShowCheckedModeBanner: false,
            home: Loading(),
          );
        }

        if (snapshot.hasError) {
          log('Firebase error: ${snapshot.error}');
          return MaterialApp(
            debugShowCheckedModeBanner: false,
            title: 'ParkPlace',
            theme: ThemeData(primarySwatch: Colors.blue),
            routes: {
              '/mainPage': (context) => MainPage(),
            },
            home: MainPage(),
          );
        }

        return MaterialApp(
          debugShowCheckedModeBanner: false,
          title: 'ParkPlace',
          theme: ThemeData(primarySwatch: Colors.blue),
          routes: {
            '/detailsScreen': (context) => DetailsScreen(),
            '/mainPage': (context) => MainPage(),
          },
          home: StreamBuilder(
            stream: FirebaseAuth.instance.authStateChanges(),
            builder: (context, userSnapshot) {
              if (userSnapshot.connectionState == ConnectionState.waiting) {
                return Loading();
              } else if (owner && userSnapshot.data != null) {
                log('Logged in as owner');
                return StreamBuilder(
                  stream: FirebaseFirestore.instance
                      .collection("giveplaceusers")
                      .doc(FirebaseAuth.instance.currentUser!.phoneNumber)
                      .snapshots(),
                  builder: (context, snapShot) {
                    if (snapShot.connectionState == ConnectionState.waiting) {
                      return Loading();
                    }
                    if (snapShot.hasData && snapShot.data!.exists) {
                      return Home();
                    }
                    return DetailsScreen();
                  },
                );
              } else if (!owner && userSnapshot.data != null) {
                log('Logged in as user');
                return StreamBuilder(
                  stream: FirebaseFirestore.instance
                      .collection("parkvehicleusers")
                      .doc(FirebaseAuth.instance.currentUser!.phoneNumber)
                      .snapshots(),
                  builder: (context, snapShot) {
                    if (snapShot.connectionState == ConnectionState.waiting) {
                      return Loading();
                    }
                    if (snapShot.hasData && snapShot.data!.exists) {
                      return HomeUser();
                    }
                    return ParkDetailsScreen();
                  },
                );
              }
              return MainPage();
            },
          ),
        );
      },
    );
  }
}

